INSERT INTO beritas (title, category, sub_category, author, excerpt, content, image, published_at, is_active, created_at, updated_at) VALUES ('6 Hari Lagi Pendaftaran Akan Ditutup  APLIKASI ASEAN ENGINEER BATCH 1/2026', 'Sertifikat Internasional', NULL, 'Septya Sekar', 'Pendaftaran APLIKASI ASEAN ENGINEER BATCH 1/2026 – MIDTERM MEETING AFEO akan segera ditutup! 🌏👷‍♂️👷‍♀️ Jangan lewatkan kesempatan untuk menjadi bagian dari insinyur profesional yang diakui di tingkat ASEAN dan memperluas jejaring keinsinyuran internasional. 📌 Deadline Pendaftaran 🗓️ 27 Mei 2026 ⏰ Pukul 17.00 WIB 📲 Link pendaftaran: https://tinyurl.com/PIIAER2026 atau scan QR Code pada poster 📄 Tidak perlu pengiriman hardcopy dokumen.', 'Pendaftaran APLIKASI ASEAN ENGINEER BATCH 1/2026 – MIDTERM MEETING AFEO akan segera ditutup! 🌏👷‍♂️👷‍♀️ Jangan lewatkan kesempatan untuk menjadi bagian dari insinyur profesional yang diakui di tingkat ASEAN dan memperluas jejaring keinsinyuran internasional. 📌 Deadline Pendaftaran 🗓️ 27 Mei 2026 ⏰ Pukul 17.00 WIB 📲 Link pendaftaran: https://tinyurl.com/PIIAER2026 atau scan QR Code pada poster 📄 Tidak perlu pengiriman hardcopy dokumen. 💳 Pembayara: Bank Mandiri No. Rekening: 070-00-0994555-6 a.n. Persatuan Insinyur Indonesia ⚠️ Formulir yang dikirim setelah 27 Mei 2026 akan diikutsertakan pada Batch II/2026. 📞 PIC Pendaftaran: PIC : Sdri. Rahma WA : +6282190276169 Email : rahma.lski@pii.or.id / info@pii.or.id Segera lengkapi persyaratan dan ajukan aplikasi terbaikmu sebelum waktu berakhir! 🚀 #ASEANEngineer #AFEO #PII #InsinyurIndonesia #reindustrialisasi', 'uploads/beritas/berita_01_6-hari-lagi-pendaftaran-akan-ditutup-apl.jpeg', '2026-05-21 09:28:13', 1, '2026-05-22 16:08:25', '2026-05-22 16:08:25');
INSERT INTO beritas (title, category, sub_category, author, excerpt, content, image, published_at, is_active, created_at, updated_at) VALUES ('PII Jawa Timur Gelar Muswil, Gentur Prihantono Kembali Terpilih sebagai Ketua', 'Muswil', NULL, 'Septya Sekar', 'Persatuan Insinyur Indonesia (PII) menghadiri Musyawarah Wilayah (Muswil) PII Jawa Timur yang diwakili oleh Sekretaris Jenderal PII, Dr. Ir. Teguh Haryono, MBA., IPU., ACPE., ASEAN Eng., APEC Eng.', 'Persatuan Insinyur Indonesia (PII) menghadiri Musyawarah Wilayah (Muswil) PII Jawa Timur yang diwakili oleh Sekretaris Jenderal PII, Dr. Ir. Teguh Haryono, MBA., IPU., ACPE., ASEAN Eng., APEC Eng. Kegiatan ini turut dihadiri Wakil Gubernur Jawa Timur, Emil Elestianto Dardak, serta sejumlah tokoh dan pengurus PII dari berbagai wilayah. (10/5/2026) Dalam Muswil tersebut, Dr. Ir. Gentur Prihantono Sandjoyo Putro, ST., SH., MT., MH., IPU., ASEAN Eng kembali terpilih sebagai Ketua PII Wilayah Jawa Timur periode 2026–2029 setelah memperoleh 35 suara dari total 58 suara sah. Pada kesempatan tersebut, Wakil Gubernur Jawa Timur Emil Elestianto Dardak menegaskan pentingnya peran insinyur dalam mendukung pembangunan daerah dan mewujudkan Jawa Timur sebagai “Gerbang Nusantara” melalui kolaborasi serta SDM keinsinyuran yang unggul dan profesional. Muswil ini juga menjadi momentum memperkuat sinergi dan kolaborasi antarinsinyur untuk menghadirkan inovasi serta kontribusi nyata bagi masyarakat, bangsa, dan negara. #PII #PersatuanInsinyurIndonesia #PIIJawaTimur #MuswilPII #InsinyurIndonesia', 'uploads/beritas/berita_02_pii-jawa-timur-gelar-muswil-gentur-priha.jpeg', '2026-05-12 07:39:28', 1, '2026-05-22 16:08:25', '2026-05-22 16:08:25');
INSERT INTO beritas (title, category, sub_category, author, excerpt, content, image, published_at, is_active, created_at, updated_at) VALUES ('Tragedi di Bekasi Timur bukan sekadar insiden ini adalah pengingat bahwa keselamatan dalam sistem perkeretaapian tidak boleh ditawar.', 'Teknologi', NULL, 'Septya Sekar', 'Tragedi di Bekasi Timur bukan sekadar insiden ini adalah pengingat bahwa keselamatan dalam sistem perkeretaapian tidak boleh ditawar. Melalui Podcast NGOPI (Ngobrol Bareng PII), kita diajak melihat lebih dalam: apa yang sebenarnya terjadi? Apakah ini murni kesalahan manusia, atau ada celah dalam sistem yang perlu segera diperbaiki?', 'Tragedi di Bekasi Timur bukan sekadar insiden ini adalah pengingat bahwa keselamatan dalam sistem perkeretaapian tidak boleh ditawar. Melalui Podcast NGOPI (Ngobrol Bareng PII), kita diajak melihat lebih dalam: apa yang sebenarnya terjadi? Apakah ini murni kesalahan manusia, atau ada celah dalam sistem yang perlu segera diperbaiki? Bersama Dr. Ir. Hermanto Dwiatmoko, MSTr., IPU., ASEAN Eng. Selaku Ketua Badan Kejuruan Teknik Perkeretaapian (BKTKA-PII) Dipandu oleh host Ir. Dandung S. Harninto, ST., IPU., ASEAN Eng. Karena dari setiap tragedi, selalu ada pelajaran yang tidak boleh diabaikan. 🎥 Tonton di YouTube pii.official #NGOPI #PII #KAI #BekasiTimur #perkeretaapian', 'uploads/beritas/berita_03_tragedi-di-bekasi-timur-bukan-sekadar-in.png', '2026-05-07 05:01:28', 1, '2026-05-22 16:08:25', '2026-05-22 16:08:25');
INSERT INTO beritas (title, category, sub_category, author, excerpt, content, image, published_at, is_active, created_at, updated_at) VALUES ('Indeks Keinsinyuran hingga  Giant Sea Wall Dibahas dalam Audiensi Bersama Pemprov DKI Jakarta dan PII', 'Audiensi', NULL, 'Septya Sekar', 'Pengurus Pusat Persatuan Insinyur Indonesia (PII) yang dipimpin oleh Sekretaris Jenderal PII, Dr. Ir. Teguh Haryono, MBA., ASEAN Eng., melakukan audiensi dengan Koordinator Staf Khusus Pemerintah Provinsi Daerah Khusus Jakarta, Prof.', 'Pengurus Pusat Persatuan Insinyur Indonesia (PII) yang dipimpin oleh Sekretaris Jenderal PII, Dr. Ir. Teguh Haryono, MBA., ASEAN Eng., melakukan audiensi dengan Koordinator Staf Khusus Pemerintah Provinsi Daerah Khusus Jakarta, Prof. Dr. Ir. Firdaus Ali, di Kantor Gubernur Jakarta pada Jumat (24/04/2026). Pertemuan ini diawali dengan pembahasan pelaksanaan pengukuran Indeks Keinsinyuran Pemerintahan oleh PII, yang menjadi salah satu instrumen penting dalam mendorong tata kelola keinsinyuran di sektor publik. Selain itu, turut dibahas rencana pembangunan Giant Sea Wall di pesisir utara Jakarta serta permasalahan dan penanganan sampah di Jakarta. Turut hadir dalam audiensi tersebut Direktur Eksekutif PII, Ir. Santhi H. Serad, M.Sc., IPU., ASEAN Eng., Ketua Tim Indeks Keinsinyuran PII Ir. Handoko, serta para anggota tim yakni Ir. M. Yanuar J. Purwanto, Ph.D., IPU., ASEAN Eng., Ir. Dandung Sri Harninto, M.T., IPU., ASEAN Eng., Ir. Faizal Safa, S.T., M.T., IPU., ASEAN Eng., dan Abdul Rahman Ma’mun. Audiensi ini menjadi bagian dari upaya PII dalam mendorong kontribusi keinsinyuran terhadap pembangunan berkelanjutan dan solusi atas tantangan perkotaan di Jakarta. #PII #PersatuanInsinyurIndonesia #InsinyurIndonesia #reindustrialisasi #Keinsinyuran', 'uploads/beritas/berita_04_indeks-keinsinyuran-hingga-giant-sea-wal.jpeg', '2026-05-05 03:03:35', 1, '2026-05-22 16:08:25', '2026-05-22 16:08:25');
INSERT INTO beritas (title, category, sub_category, author, excerpt, content, image, published_at, is_active, created_at, updated_at) VALUES ('Pelantikan dan Pengambilan Sumpah PSPPI Fakultas Teknik Universitas Katolik Widya Mandala Surabaya Tahun Akademik 2025/2026', 'Pelantikan PSPPI', NULL, 'Septya Sekar', 'Pelantikan dan Pengambilan Sumpah Profesi Insinyur Program Studi Program Profesi Insinyur (PSPPI) Fakultas Teknik Universitas Katolik Widya Mandala Surabaya Tahun Akademik 2025/2026 telah dilaksanakan dengan khidmat pada sabtu, 18 April 2026. Dalam kesempatan ini, Persatuan Insinyur Indonesia (PII) diwakili oleh Sekretaris Jenderal PII, Dr. Ir.', 'Pelantikan dan Pengambilan Sumpah Profesi Insinyur Program Studi Program Profesi Insinyur (PSPPI) Fakultas Teknik Universitas Katolik Widya Mandala Surabaya Tahun Akademik 2025/2026 telah dilaksanakan dengan khidmat pada sabtu, 18 April 2026. Dalam kesempatan ini, Persatuan Insinyur Indonesia (PII) diwakili oleh Sekretaris Jenderal PII, Dr. Ir. Teguh Haryono, MBA., IPU., ASEAN Eng., ACPE., APEC Eng. yang hadir secara langsung. Momentum ini menjadi tonggak penting bagi para lulusan dalam mengemban tanggung jawab sebagai insinyur profesional, sekaligus memperkuat komitmen dalam menjunjung tinggi etika dan kontribusi nyata bagi pembangunan bangsa. Selamat kepada para insinyur baru, terus berkarya dan berkontribusi untuk Indonesia. #PII #PSPPI #InsinyurIndonesia #UniversitasMulawarman #engineering', 'uploads/beritas/berita_05_pelantikan-dan-pengambilan-sumpah-psppi.jpeg', '2026-04-24 07:14:50', 1, '2026-05-22 16:08:25', '2026-05-22 16:08:25');
INSERT INTO beritas (title, category, sub_category, author, excerpt, content, image, published_at, is_active, created_at, updated_at) VALUES ('PII turut menghadiri 67th Annual Dinner & Awards Night 2026 yang diselenggarakan oleh The Institution of Engineers, Malaysia (IEM)', 'Meeting', NULL, 'Septya Sekar', 'Persatuan Insinyur Indonesia (PII) turut menghadiri 67th Annual Dinner & Awards Night 2026 yang diselenggarakan oleh The Institution of Engineers, Malaysia (IEM) di Sunway Resort Hotel, Petaling Jaya Malaysia (18/04). Direktur Eksekutif PII, Ir. Santhi H.', 'Persatuan Insinyur Indonesia (PII) turut menghadiri 67th Annual Dinner & Awards Night 2026 yang diselenggarakan oleh The Institution of Engineers, Malaysia (IEM) di Sunway Resort Hotel, Petaling Jaya Malaysia (18/04). Direktur Eksekutif PII, Ir. Santhi H. Serad, M.Sc., IPU., ASEAN Eng, hadir bersama Deputi Ketua Umum PII Bidang Kerja Sama Keinsinyuran Internasional, Ir. Andre Mulpyana, BSIE., MSIE., IPU. Turut hadir pula Ketua Badan Keahlian Sipil (BKS) PII, Ir. Habibie Razak, APEC Eng., CPEng., FIEAust., EngExec., IntPE (Aus), serta Perwakilan Luar Negeri (PLN) PII Malaysia, Ir. Asep Nurul Haq, ST., MSc., ASEAN Eng, bersama para pemangku kepentingan strategis lainnya. Acara ini juga dihadiri oleh Menteri Science, Technology and Innovation Malaysia, YBhg. Datuk Seri Hj. Hasnol Zam Zam bin Hj. Ahmad, yang semakin menegaskan pentingnya kolaborasi lintas negara dalam penguatan profesi keinsinyuran. Mengusung tema “Connecting Engineering Practitioners”, kegiatan ini menjadi momentum untuk mempererat jejaring, mendorong kolaborasi, serta memperkuat peran insinyur dalam pembangunan berkelanjutan di kawasan ASEAN. #PII #reindustrialisasi #AER #Engineering #ASEAN', 'uploads/beritas/berita_06_pii-turut-menghadiri-67th-annual-dinner.png', '2026-04-24 07:08:55', 1, '2026-05-22 16:08:25', '2026-05-22 16:08:25');
INSERT INTO beritas (title, category, sub_category, author, excerpt, content, image, published_at, is_active, created_at, updated_at) VALUES ('PII Perkuat Koordinasi CAFEO 44 di AFEO Sekretariat', 'AFEO', NULL, 'Septya Sekar', 'Direktur Eksekutif Persatuan Insinyur Indonesia (PII), Ir. Santhi H. Serad, M.Sc., IPU., ASEAN Eng, mengunjungi dan melakukan rapat koordinasi dengan Sekretaris Jenderal The ASEAN Federation of Engineering Organisations (AFEO), Dr.', 'Direktur Eksekutif Persatuan Insinyur Indonesia (PII), Ir. Santhi H. Serad, M.Sc., IPU., ASEAN Eng, mengunjungi dan melakukan rapat koordinasi dengan Sekretaris Jenderal The ASEAN Federation of Engineering Organisations (AFEO), Dr. Ir. David Chua, ASEAN Eng, di kantor Sekretariat AFEO yang berkedudukan di The Institution of Engineers, Malaysia (IEM), Petaling Jaya, Selangor, Malaysia, Sabtu (18 April 2026). Pertemuan tersebut turut dihadiri oleh President of The Institution of Engineers, Malaysia, Ir. Simon Yeong Chin Chow, ASEAN Eng,. serta Deputi Ketua Umum PII Bidang Kerja Sama Keinsinyuran Internasional, Ir. Andre Mulpyana, BSIE., MSIE., IPU. Dalam pertemuan ini dibahas perkembangan dan kesiapan Persatuan Insinyur Indonesia sebagai tuan rumah penyelenggaraan Conference of the ASEAN Federation of Engineering Organisations ke-44 di Bandung, Indonesia, yang direncanakan berlangsung pada Oktober 2026, termasuk berbagai persiapan teknis pelaksanaan. Kunjungan ini menjadi bagian dari upaya memperkuat koordinasi dan kolaborasi regional guna menyukseskan konferensi insinyur terbesar di kawasan ASEAN. #PII #Engineering #ASEAN #CAFEO44 #AFEO', 'uploads/beritas/berita_07_pii-perkuat-koordinasi-cafeo-44-di-afeo.png', '2026-04-24 06:59:43', 1, '2026-05-22 16:08:25', '2026-05-22 16:08:25');
INSERT INTO beritas (title, category, sub_category, author, excerpt, content, image, published_at, is_active, created_at, updated_at) VALUES ('Pertemuan yang produktif dalam kerangka Indonesia–Malaysia–Thailand Growth Triangle (IMT-GT) di Kuala Lumpur,', 'Audiensi', NULL, 'Septya Sekar', 'Pertemuan yang produktif dalam kerangka Indonesia–Malaysia–Thailand Growth Triangle (IMT-GT) di Kuala Lumpur, yang dihadiri oleh Ir. Santhi H. Serad, M.Sc., IPU., ASEAN Eng.', 'Pertemuan yang produktif dalam kerangka Indonesia–Malaysia–Thailand Growth Triangle (IMT-GT) di Kuala Lumpur, yang dihadiri oleh Ir. Santhi H. Serad, M.Sc., IPU., ASEAN Eng. dan Ir. Andre Mulpyana, BSIE., MSIE., IPU., membahas potensi kolaborasi antara Persatuan Insinyur Indonesia (PII), Institution of Engineers Malaysia (IEM), dan Engineering Institute of Thailand (EIT) dalam mendukung pengembangan IMT-GT. Terima kasih kepada Ibu Sindu Rahayu, S.I.P., M.Si., M.H., M.B.A. atas dukungan yang penuh antusias sebagai Atase Perhubungan Kedutaan Besar Republik Indonesia. Kolaborasi antara pemerintah, masyarakat, dan akademisi akan menjadikan program IMT-GT semakin sukses. #PII #IMTGT #KolaborasiRegional #InsinyurIndonesia #EngineeringForNation', 'uploads/beritas/berita_08_pertemuan-yang-produktif-dalam-kerangka.jpeg', '2026-04-22 09:47:59', 1, '2026-05-22 16:08:25', '2026-05-22 16:08:25');
INSERT INTO beritas (title, category, sub_category, author, excerpt, content, image, published_at, is_active, created_at, updated_at) VALUES ('PII turut menghadiri Peluncuran & Diskusi Buku “Dari Loyang Jadi Emas”,', 'Pelayanan', NULL, 'Septya Sekar', 'Persatuan Insinyur Indonesia (PII) turut menghadiri Peluncuran & Diskusi Buku “Dari Loyang Jadi Emas”, karya kolaboratif BK Kimia PII bersama asosiasi dan industri sawit. Buku ini mengangkat kisah inspiratif Sahat M. Sinaga dalam mendorong peningkatan nilai tambah industri sawit Indonesia, dari komoditas mentah menjadi produk bernilai tinggi yang berdaya saing global.', 'Persatuan Insinyur Indonesia (PII) turut menghadiri Peluncuran & Diskusi Buku “Dari Loyang Jadi Emas”, karya kolaboratif BK Kimia PII bersama asosiasi dan industri sawit. Buku ini mengangkat kisah inspiratif Sahat M. Sinaga dalam mendorong peningkatan nilai tambah industri sawit Indonesia, dari komoditas mentah menjadi produk bernilai tinggi yang berdaya saing global. Kegiatan ini dihadiri oleh Menteri PPN/Kepala Bappenas Dr. Rachmat Pambudy, serta jajaran Persatuan Insinyur Indonesia, di antaranya: Prof. Dr. Ir. Agus Taufik Mulyono, S.T., M.T., IPU., ASEAN Eng. (Wakil Ketua Umum PII), Dr. Ir. Teguh Haryono, S.T., MBA., IPU., ASEAN Eng., APEC Eng. (Sekretaris Jenderal PII), Ir. Santhi H. Serad, M.Sc., IPU., ASEAN Eng. (Direktur Eksekutif PII), Dr. Ir. Sripeni Inten Cahyani, M.M., IPM., ASEAN Eng., (Ketua BK Kimia) serta Ir. Gilarsi W. Setjono, (Deputi Ketua Umum Reindustrialisasi PII) bersama para pemangku kepentingan lainnya. Melalui momentum ini, PII menegaskan komitmennya dalam mendorong peran insinyur Indonesia untuk memperkuat hilirisasi industri, khususnya sektor sawit, melalui inovasi dan kolaborasi lintas sektor. #PII #InsinyurIndonesia #Hilirisasi #IndustriSawit #Bappenas', 'uploads/beritas/berita_09_pii-turut-menghadiri-peluncuran-diskusi.jpg', '2026-04-17 07:36:38', 1, '2026-05-22 16:08:25', '2026-05-22 16:08:25');
INSERT INTO beritas (title, category, sub_category, author, excerpt, content, image, published_at, is_active, created_at, updated_at) VALUES ('PII Wilayah Jawa Timur menyelenggarakan Rapimwil yang berangkaian dengan kegiatan Halal Bihalal 1447 H pada Sabtu, 11 April 2026', 'Pelayanan', NULL, 'Septya Sekar', 'Persatuan Insinyur Indonesia (PII) Wilayah Jawa Timur menyelenggarakan Rapat Pimpinan Wilayah (Rapimwil) yang berangkaian dengan kegiatan Halal Bihalal 1447 H pada Sabtu, 11 April 2026 di Surabaya. Kegiatan ini menjadi momen penting untuk mempererat silaturahmi antarinsinyur sekaligus memperkuat arah organisasi ke depan. Dalam kesempatan ini, Sekretaris Jenderal PP PII, Dr.', 'Persatuan Insinyur Indonesia (PII) Wilayah Jawa Timur menyelenggarakan Rapat Pimpinan Wilayah (Rapimwil) yang berangkaian dengan kegiatan Halal Bihalal 1447 H pada Sabtu, 11 April 2026 di Surabaya. Kegiatan ini menjadi momen penting untuk mempererat silaturahmi antarinsinyur sekaligus memperkuat arah organisasi ke depan. Dalam kesempatan ini, Sekretaris Jenderal PP PII, Dr. Ir. Teguh Haryono, MBA., IPU., ASEAN Eng., turut hadir dan memberikan pemaparan mengenai “Tren Perkembangan Budaya Organisasi yang Maju & Berkelanjutan”. Ketua PW PII Jawa Timur Dr. Ir. Gentur Prihantono, SP., ST., SH., MT., MH., IPU., ASEAN Eng. juga hadir memberi sambutan. Melalui kegiatan ini, diharapkan semangat kebersamaan pasca Idulfitri dapat menjadi energi baru dalam menjalankan program kerja organisasi, sekaligus memperkuat peran insinyur dalam pembangunan yang berkelanjutan. #PII #PIIJatim #HalalBihalal #RapimwilPII', 'uploads/beritas/berita_10_pii-wilayah-jawa-timur-menyelenggarakan.png', '2026-04-17 07:29:55', 1, '2026-05-22 16:08:25', '2026-05-22 16:08:25');
INSERT INTO beritas (title, category, sub_category, author, excerpt, content, image, published_at, is_active, created_at, updated_at) VALUES ('Persatuan Insinyur Indonesia (PII) menerima kunjungan dari The Institution of Engineers Singapore', 'Meeting', NULL, 'Septya Sekar', 'Persatuan Insinyur Indonesia (PII) menerima kunjungan dari The Institution of Engineers Singapore di Kantor Pengurus Pusat PII, Graha Rekayasa Indonesia. Pertemuan ini menjadi ajang silaturahmi sekaligus diskusi terkait perkembangan dunia keinsinyuran di masing-masing negara. (10/4/2026) Kegiatan ini dihadiri oleh jajaran pimpinan PII, yaitu wakil ketua umum PII Prof.', 'Persatuan Insinyur Indonesia (PII) menerima kunjungan dari The Institution of Engineers Singapore di Kantor Pengurus Pusat PII, Graha Rekayasa Indonesia. Pertemuan ini menjadi ajang silaturahmi sekaligus diskusi terkait perkembangan dunia keinsinyuran di masing-masing negara. (10/4/2026) Kegiatan ini dihadiri oleh jajaran pimpinan PII, yaitu wakil ketua umum PII Prof. Dr. Ir. Agus Taufik Mulyono, ST., MT., IPU., ASEAN Eng., sekretaris jenderal PII Dr. Ir. Teguh Haryono, ST., MBA., IPU., ASEAN Eng., APEC Eng., Ir. Andre Mulpyana, BSIE., MSIE., IPU., Ir. Dandung Sri Harninto, MT., IPU., ASEAN Eng., Ir. Santhi H. Serad, M.Sc., IPU., ASEAN Eng. selaku Direktur Eksekutif PII, serta Ir. Haudhi Ramdhayuza, ST., IPU. Wakil sekretaris jenderal PII Dalam suasana yang hangat, kedua pihak saling berbagi pandangan mengenai tantangan dan peluang profesi insinyur ke depan. Mulai dari peningkatan kompetensi, peran insinyur dalam pembangunan, hingga pentingnya memperluas jejaring antarinsinyur di kawasan ASEAN. Melalui pertemuan ini, PII terus mendorong ruang diskusi dan pertukaran wawasan agar insinyur Indonesia semakin siap menghadapi perkembangan global dan tetap relevan di berbagai sektor. #PII #InsinyurIndonesia #IESSingapore #reindustrialisasi #aseanengineer', 'uploads/beritas/berita_11_persatuan-insinyur-indonesia-pii-menerim.jpg', '2026-04-17 04:34:59', 1, '2026-05-22 16:08:25', '2026-05-22 16:08:25');
INSERT INTO beritas (title, category, sub_category, author, excerpt, content, image, published_at, is_active, created_at, updated_at) VALUES ('Webinar GOES 2.0 III Bahas Regulasi Data Center untuk Mendukung Infrastruktur Digital Indonesia', 'Sertifikat Internasional', NULL, 'Septya Sekar', 'Makassar, 31 Maret 2026 – Global Outreach Series (GOES 2.0) III kembali diselenggarakan sebagai bagian dari kolaborasi regional di bidang keinsinyuran. Kegiatan ini diinisiasi oleh AEI – Electrical Installation Steering Committee (EISC) bekerja sama dengan Persatuan Insinyur Indonesia (PII), dengan mengangkat tema “Data Center Regulation in Indonesia: Building a Secure and Competitive Digital Infrastructure.” Webinar ini menghadirkan narasumber utama, Dr. Ir.', 'Makassar, 31 Maret 2026 – Global Outreach Series (GOES 2.0) III kembali diselenggarakan sebagai bagian dari kolaborasi regional di bidang keinsinyuran. Kegiatan ini diinisiasi oleh AEI – Electrical Installation Steering Committee (EISC) bekerja sama dengan Persatuan Insinyur Indonesia (PII), dengan mengangkat tema “Data Center Regulation in Indonesia: Building a Secure and Competitive Digital Infrastructure.” Webinar ini menghadirkan narasumber utama, Dr. Ir. Denny Setiawan, Director of Digital Infrastructure Strategy and Policy, Kementerian Komunikasi dan Digital (KOMDIGI) Republik Indonesia. Kegiatan ini dipandu oleh Assoc. Prof. Ir. Sirmayanti, IPU, ASEAN Eng, APEC Eng  selaku Head of Indonesian Representative AEI – Electrical Installation serta Vice Chair for Institutional Relations and Regulatory BKE PII, dan dibuka secara resmi oleh Ir. Dr. Siow Chun Lim, Chairman of ASEAN Engineering Inspectors – Electrical Installation. Dalam sambutannya, Ir. Dr. Siow Chun Lim menekankan pentingnya kolaborasi antar negara ASEAN dalam memperkuat standar dan praktik keinsinyuran, khususnya dalam menghadapi perkembangan teknologi digital yang semakin pesat. Dalam paparannya, Dr. Denny Setiawan menyampaikan bahwa transformasi digital di Indonesia telah meningkatkan kebutuhan terhadap infrastruktur data center yang andal, aman, dan skalabel. Pemerintah Indonesia telah mengembangkan berbagai kebijakan strategis yang mencakup perlindungan data, keamanan siber, serta penguatan ekosistem digital nasional. Lebih lanjut, beliau juga menjelaskan pentingnya pengembangan roadmap nasional data center sebagai bagian dari upaya mendukung pertumbuhan ekonomi digital, serta menciptakan iklim investasi yang kompetitif di sektor infrastruktur digital. Webinar ini juga menyoroti tantangan dalam menyeimbangkan antara kepatuhan regulasi, inovasi teknologi, dan daya tarik investasi. Diskusi yang berlangsung interaktif pada sesi tanya jawab menunjukkan tingginya antusiasme peserta dari berbagai latar belakang, baik akademisi, praktisi industri, maupun pemangku kebijakan. Kegiatan ini juga mencerminkan peran aktif PII dalam mendukung pengembangan profesi keinsinyuran di Indonesia, serta kontribusinya di tingkat regional melalui ASEAN Federation of Engineering Organizations (AFEO). Dalam konteks ini, Electrical Installation Steering Committee (EISC) sebagai salah satu working group di AFEO memiliki peran strategis dalam mendorong harmonisasi standar dan praktik instalasi listrik di kawasan ASEAN. Melalui kegiatan ini, diharapkan terbangun pemahaman yang lebih komprehensif terkait regulasi data center, serta memperkuat sinergi antar pemangku kepentingan dalam membangun infrastruktur digital yang aman, kompetitif, dan berkelanjutan. Kegiatan ditutup dengan sesi foto bersama sebagai simbol kolaborasi dan komitmen bersama dalam pengembangan ekosistem digital di tingkat nasional dan regional.', 'uploads/beritas/berita_12_webinar-goes-20-iii-bahas-regulasi-data.jpeg', '2026-04-02 02:12:56', 1, '2026-05-22 16:08:25', '2026-05-22 16:08:25');
INSERT INTO beritas (title, category, sub_category, author, excerpt, content, image, published_at, is_active, created_at, updated_at) VALUES ('PII Riau Gelar Buka Puasa Bersama dan Executive Talk Bahas Ketahanan Energi Nasional', 'Sarasehan & FGD', NULL, 'PW Riau', 'Pekanbaru,13/03/2026– Persatuan Insinyur Indonesia (PII) Wilayah Provinsi Riau menggelar kegiatan Buka Puasa Bersama yang dirangkaikan dengan Executive Talk Pengurus Wilayah PII Riau serta Peluncuran Buku, pada Jum’at, 13 Maret 2026 di Cititel Hotel Pekanbaru. Kegiatan ini dihadiri oleh berbagai tokoh penting di bidang keinsinyuran dan pembangunan daerah, di antaranya Ketua Lembaga Pengembangan Jasa Konstruksi (LPJK) Periode 2025–2029 Ir. Insannul Kamil, M.Eng., Ph.D., IPU., ASEAN Eng., APEC Eng', 'Pekanbaru,13/03/2026– Persatuan Insinyur Indonesia (PII) Wilayah Provinsi Riau menggelar kegiatan Buka Puasa Bersama yang dirangkaikan dengan Executive Talk Pengurus Wilayah PII Riau serta Peluncuran Buku, pada Jum’at, 13 Maret 2026 di Cititel Hotel Pekanbaru. Kegiatan ini dihadiri oleh berbagai tokoh penting di bidang keinsinyuran dan pembangunan daerah, di antaranya Ketua Lembaga Pengembangan Jasa Konstruksi (LPJK) Periode 2025–2029 Ir. Insannul Kamil, M.Eng., Ph.D., IPU., ASEAN Eng., APEC Eng, Anggota LPJK Periode 2025–2029 Muhammad Ikhsan, ST., M.Sc., Ph.D, serta Kepala Balai Pelaksanaan Jalan Nasional (BPJN) Provinsi Riau Dr. Ir. Yohanis Tulak Todingrara, ST., MT. Turut hadir Dewan Pembina PII Wilayah Provinsi Riau sekaligus Ketua Umum DPP Asosiasi Pelaksana Konstruksi Nasional (ASPEKNAS) H. Aswandi, SE, Dewan Penasehat dan Dewan Pakar PII Wilayah Riau, para Ketua PII Cabang se-Provinsi Riau, jajaran pengurus PII Wilayah Provinsi Riau, Forum Insinyur Muda (FIM) PII Riau, akademisi, serta mahasiswa dari berbagai perguruan tinggi di Provinsi Riau. Kegiatan ini mengusung tema “Silaturahmi Ramadhan dan Refleksi Ketahanan Energi serta Infrastruktur Nasional”, yang dirangkaikan dengan Executive Talk bertema “Ketahanan Energi Nasional dalam Perspektif Geopolitik Global dan Pembangunan Infrastruktur: Dampak Geopolitik terhadap Rantai Pasok Energi dan Konstruksi.” Dalam sambutannya, Ketua PII Wilayah Provinsi Riau Ir. Ulul Azmi, ST., M.Si., CST., IPM., ASEAN Eng menyampaikan bahwa kegiatan ini merupakan momentum silaturahmi sekaligus refleksi peran insinyur dalam menghadapi tantangan pembangunan di tengah dinamika geopolitik global. Menurutnya, kondisi dunia saat ini yang diwarnai konflik geopolitik, termasuk eskalasi konflik di kawasan Timur Tengah, memberikan dampak besar terhadap stabilitas energi dunia. Hal ini tentu berdampak pada negara-negara yang masih memiliki ketergantungan terhadap energi impor, termasuk Indonesia. “Ketika konflik terjadi di kawasan strategis seperti Timur Tengah yang menjadi jalur utama perdagangan energi dunia, maka dampaknya akan langsung dirasakan oleh negara-negara pengimpor energi. Hal ini akan mempengaruhi harga energi global, rantai pasok material konstruksi, serta biaya pembangunan infrastruktur,” ujar Ulul Azmi. Ia juga menegaskan bahwa Indonesia memiliki potensi sumber daya yang sangat besar. Provinsi Riau sendiri merupakan salah satu wilayah strategis dalam sektor energi nasional dengan potensi sumber daya alam yang melimpah serta posisi penting dalam industri energi dan pembangunan infrastruktur. Menurutnya, kondisi tersebut harus menjadi momentum bagi para insinyur untuk meningkatkan kompetensi serta berkontribusi nyata dalam pembangunan nasional. Dalam kesempatan tersebut, Ketua PII Riau juga menyampaikan perkembangan organisasi PII Riau yang menunjukkan kemajuan signifikan dalam beberapa tahun terakhir. Saat ini PII Riau memiliki lebih dari 2.000 anggota aktif yang tersebar di 10 cabang pada 12 kabupaten/kota, dengan sekitar 30 persen anggota telah tersertifikasi sebagai Insinyur Profesional (Pratama, Madya, dan Utama) serta sekitar 30 insinyur telah memperoleh pengakuan ASEAN Engineer. Sepanjang tahun 2025, PII Riau juga telah menjalankan berbagai program strategis, di antaranya konsolidasi organisasi wilayah dan cabang, kolaborasi dengan perguruan tinggi dan instansi pemerintah, forum ilmiah dan kebijakan, aksi sosial dan lingkungan melalui kampanye Green Engineer, serta kegiatan peringatan HUT PII ke-73 dengan penanaman 1.000 pohon sebagai bentuk komitmen terhadap pembangunan berkelanjutan. Selain itu, pada kesempatan tersebut PII Riau juga memberikan penghargaan kepada beberapa PII Cabang di Provinsi Riau yang dinilai aktif dan memberikan kontribusi besar dalam pengembangan organisasi dan peran insinyur di daerah. Penghargaan ini merupakan bentuk apresiasi atas dedikasi cabang-cabang yang aktif, sekaligus menjadi motivasi bagi seluruh cabang untuk terus berkontribusi bagi kemajuan organisasi. Sementara itu, Dewan Pembina PII Wilayah Riau H. Aswandi, SE dalam sambutannya menyampaikan apresiasi terhadap berbagai inovasi dan kolaborasi yang telah dilakukan oleh PII Riau. Menurutnya, dalam kurun waktu sekitar satu setengah tahun perjalanan kepengurusan PII Riau Periode 2024–2027, terlihat banyak langkah progresif yang dilakukan melalui sinergi organisasi, penguatan kolaborasi dengan berbagai pihak, serta komitmen kuat dalam mendorong peran insinyur dalam pembangunan daerah. Lebih lanjut, H. Aswandi juga menilai bahwa perkembangan PII Riau menunjukkan dinamika organisasi yang sangat baik dan progresif. “Saya mengikuti perjalanan PII Riau selama lebih kurang satu setengah tahun atau sekitar setengah periode kepengurusan saat ini. Jika dibandingkan dengan beberapa wilayah lain, PII Riau menunjukkan dinamika organisasi yang sangat baik. Banyak inovasi program, kolaborasi lintas sektor, serta komitmen kuat dari pengurus wilayah yang didukung penuh oleh seluruh cabang se-Provinsi Riau,” ujar H. Aswandi. Ia juga menekankan bahwa peran organisasi profesi seperti PII sangat penting dalam memastikan bahwa pembangunan daerah dan nasional didukung oleh tenaga insinyur yang profesional, kompeten, serta memiliki integritas tinggi. Menurutnya, dengan potensi sumber daya alam yang dimiliki Provinsi Riau serta posisi strategisnya dalam sektor energi dan infrastruktur nasional, maka kontribusi para insinyur sangat diperlukan dalam memastikan pembangunan berjalan secara berkelanjutan dan memberikan manfaat bagi masyarakat luas. Dalam sesi Executive Talk, Ketua LPJK Ir. Insannul Kamil, M.Eng., Ph.D., IPU., ASEAN Eng., APEC Eng menyampaikan paparan mengenai ketahanan energi nasional dalam perspektif geopolitik global dan pembangunan infrastruktur. Dalam paparannya dijelaskan bahwa eskalasi konflik geopolitik global, sanksi ekonomi antarnegara, serta persaingan penguasaan sumber daya energi telah menciptakan ketidakpastian baru dalam sistem perdagangan global. Energi tidak lagi sekadar komoditas ekonomi, tetapi telah menjadi instrumen strategis dalam hubungan internasional dan keamanan nasional. Ia juga menjelaskan bahwa sektor konstruksi Indonesia memiliki ketergantungan yang cukup besar terhadap energi dan material impor seperti minyak bumi, LPG, baja konstruksi, hingga mesin konstruksi berat. Data menunjukkan bahwa nilai impor Indonesia pada tahun 2024 mencapai sekitar USD 233,65 miliar, dengan sektor energi dan bahan baku industri menjadi salah satu kontributor utama. Selain itu, konflik di kawasan Timur Tengah yang menjadi jalur utama perdagangan energi dunia juga memberikan dampak signifikan terhadap negara pengimpor energi seperti Indonesia. Sekitar 35 persen perdagangan minyak dan gas dunia melewati Selat Hormuz, sehingga setiap gangguan pada jalur tersebut dapat memicu kenaikan harga energi global dan berdampak pada biaya pembangunan infrastruktur. Paparan tersebut juga menyoroti bahwa beberapa sektor infrastruktur nasional sangat rentan terhadap fluktuasi harga energi global, di antaranya pembangunan jalan tol, pelabuhan, bandara, bendungan, serta infrastruktur energi. Sebagai bagian dari solusi strategis, disampaikan beberapa rekomendasi kebijakan, antara lain diversifikasi energi nasional melalui pengembangan energi baru dan terbarukan, penguatan cadangan energi strategis nasional, peningkatan efisiensi energi di sektor industri dan konstruksi, serta pengembangan industri material konstruksi domestik untuk mengurangi ketergantungan terhadap impor. Ia juga menekankan pentingnya kolaborasi antara pemerintah, industri konstruksi, perguruan tinggi, serta organisasi profesi keinsinyuran dalam membangun sistem pembangunan infrastruktur yang lebih tangguh terhadap risiko geopolitik global. Menurutnya, peran Lembaga Pengembangan Jasa Konstruksi (LPJK) sangat strategis dalam meningkatkan kompetensi sumber daya manusia konstruksi, memperkuat sistem sertifikasi tenaga profesional, serta memperkuat ekosistem industri konstruksi nasional. Sebagai penutup rangkaian kegiatan, peserta mengikuti tausiyah Ramadhan yang disampaikan oleh Dr. H. Asep Ajidin, S.Pd.I., SH., MH, yang memberikan pesan mengenai pentingnya integritas, amanah, serta nilai-nilai moral dalam menjalankan profesi dan kehidupan bermasyarakat. Kegiatan kemudian dilanjutkan dengan buka puasa bersama dan silaturahmi antar pengurus serta anggota PII, yang diharapkan semakin memperkuat sinergi para insinyur dalam mendukung pembangunan Provinsi Riau dan Indonesia.', 'uploads/beritas/berita_13_pii-riau-gelar-buka-puasa-bersama-dan-ex.jpg', '2026-03-14 07:37:05', 1, '2026-05-22 16:08:25', '2026-05-22 16:08:25');
INSERT INTO beritas (title, category, sub_category, author, excerpt, content, image, published_at, is_active, created_at, updated_at) VALUES ('PII Cabang Makassar Dorong Kolaborasi Atasi Persoalan Perkotaan', 'Perwakilan Wilayah PII', NULL, 'Septya Sekar', 'Persatuan Insinyur Indonesia ( PII ) Cabang Makassar menggelar rapat koordinasi yang dirangkaikan dengan buka puasa bersama pada Sabtu (7/3/2026) di Hotel Novotel Makassar. Kegiatan ini dihadiri jajaran pengurus PII Cabang Makassar periode 2024–2027 serta sejumlah anggota Forum Anggota Muda (FAM). Dalam forum tersebut, PII Cabang Makassar menyoroti sejumlah isu strategis perkotaan yang dinilai mendesak untuk ditangani secara kolaboratif, di antaranya persoalan banjir, pengelolaan sampah berbasis', 'Persatuan Insinyur Indonesia ( PII ) Cabang Makassar menggelar rapat koordinasi yang dirangkaikan dengan buka puasa bersama pada Sabtu (7/3/2026) di Hotel Novotel Makassar. Kegiatan ini dihadiri jajaran pengurus PII Cabang Makassar periode 2024–2027 serta sejumlah anggota Forum Anggota Muda (FAM). Dalam forum tersebut, PII Cabang Makassar menyoroti sejumlah isu strategis perkotaan yang dinilai mendesak untuk ditangani secara kolaboratif, di antaranya persoalan banjir, pengelolaan sampah berbasis teknologi, serta penguatan sumber daya manusia profesional di Kota Makassar. Ketua PII Cabang Makassar, Prof. Dr. Ir. Rustan Tarakka, S.T., M.T., IPM., ASEAN Eng., dalam sambutannya menyampaikan apresiasi atas kehadiran para pengurus di tengah cuaca hujan yang melanda Kota Makassar sepanjang hari. Ia mengatakan, momentum buka puasa bersama selama Ramadan telah menjadi tradisi yang tidak hanya mempererat silaturahmi, tetapi juga memperkuat koordinasi organisasi dalam menjalankan peran keinsinyuran untuk masyarakat. “Berbuka puasa bersama di bulan Ramadan telah menjadi rutinitas pengurus PII Cabang Makassar. Momentum ini diharapkan menjadi media silaturahim para pengurus yang memiliki kesibukan masing-masing, namun tetap menguatkan koordinasi untuk menyukseskan sejumlah program kerja dalam peran abdi Insinyur Profesional pada sejumlah permasalahan masyarakat Kota Makassar,” ujar Rustan, (07/03/2026). Salah satu isu utama yang menjadi perhatian dalam rapat tersebut adalah penanganan banjir di Makassar. PII Cabang Makassar menilai persoalan banjir merupakan masalah kompleks yang memerlukan pendekatan multidisipliner dan berkelanjutan. Untuk itu, organisasi profesi ini merencanakan penyelenggaraan Focus Group Discussion (FGD) yang melibatkan kalangan akademisi, praktisi, serta pemangku kepentingan pembangunan di Kota Makassar. Forum tersebut diharapkan dapat menjadi ruang bersama untuk merumuskan arah penanganan banjir secara lebih komprehensif dan berorientasi jangka panjang, dengan mempertimbangkan aspek keselamatan masyarakat dan keberlanjutan lingkungan perkotaan. Atas Sejumlah Permasalahan Teknologi Selain banjir, isu pengelolaan sampah juga menjadi agenda penting dalam pembahasan. PII Cabang Makassar mendorong penerapan teknologi pengelolaan sampah yang telah dikembangkan melalui penelitian ilmiah para pakar lingkungan. Implementasi program ini direncanakan menyasar lingkungan perguruan tinggi hingga kawasan kecamatan dan kelurahan. Menurut PII Cabang Makassar, pengelolaan sampah di lingkungan masyarakat harus memperhatikan dampak terhadap lingkungan sekaligus mengoptimalkan potensi teknologi yang tersedia agar dapat diterapkan secara efektif dan berkelanjutan. Di bidang pengembangan sumber daya manusia, PII Cabang Makassar juga menyiapkan program pelatihan dan sertifikasi profesional. Langkah ini dinilai penting untuk memperkuat kapasitas tenaga profesional serta mendukung peningkatan kualitas kerja di tengah tantangan pembangunan perkotaan yang semakin kompleks. PII Cabang Makassar berpandangan bahwa penyelesaian persoalan kota tidak hanya bertumpu pada aspek teknis, tetapi juga memerlukan perubahan perilaku masyarakat. Karena itu, peran insinyur melalui berbagai bidang keahlian dinilai strategis dalam mendorong terciptanya budaya hidup bersih dan sehat dari tingkat paling dasar di masyarakat. Kegiatan koordinasi tersebut kemudian ditutup dengan buka puasa bersama dalam suasana kebersamaan. Melalui momentum Ramadan 1447 Hijriah, PII Cabang Makassar juga mengajak masyarakat untuk terus menjaga kesehatan dan kebersihan lingkungan demi mewujudkan kota yang harmonis dan berkelanjutan. sumber: https://konstruksimedia.com/pii-cabang-makassar-dorong-kolaborasi-atasi-persoalan-perkotaan/', 'uploads/beritas/berita_14_pii-cabang-makassar-dorong-kolaborasi-at.jpeg', '2026-03-09 03:12:28', 1, '2026-05-22 16:08:25', '2026-05-22 16:08:25');
INSERT INTO beritas (title, category, sub_category, author, excerpt, content, image, published_at, is_active, created_at, updated_at) VALUES ('Pengambilan Sumpah 24 Insinyur PPI IPB', 'Pelantikan PSPPI', NULL, 'Septya Sekar', 'Sekolah Pascasarjana (SPs) IPB University melaksanakan Pengambilan Sumpah 24 Insinyur lulusan Program Profesi Insinyur (PPI) Angkatan ke-8 pada 19 Februari 2026 di Kampus SPs IPB University, Bogor. Hadir dalam acara ini Wakil Ketua Umum Persatuan Insinyur Indonesia (PII) Prof. Dr.', 'Sekolah Pascasarjana (SPs) IPB University melaksanakan Pengambilan Sumpah 24 Insinyur lulusan Program Profesi Insinyur (PPI) Angkatan ke-8 pada 19 Februari 2026 di Kampus SPs IPB University, Bogor. Hadir dalam acara ini Wakil Ketua Umum Persatuan Insinyur Indonesia (PII) Prof. Dr. Ir. Agus Taufik Mulyono, ST., MT., IPU., ASEAN Eng.,sebagai bentuk dukungan terhadap penguatan profesionalisme dan standar keinsinyuran di Indonesia. Dari 24 insinyur baru, terdapat Rektor ETCI Timor Leste. Ini menunjukkan bahwa Program Profesi Insinyur ini telah diterima masyarakat keinsinyuran internasional. Momentum ini juga menjadi simbol komitmen para insinyur profesional untuk menjunjung tinggi integritas, etika, dan tanggung jawab dalam pengabdian kepada masyarakat dan bangsa. Hingga Februari 2026, tercatat 780 insinyur telah diluluskan oleh IPB University melalui jalur reguler maupun Rekognisi Pembelajaran Lampau (RPL). Melalui Program Profesi Insinyur, IPB University berkomitmen menghasilkan insinyur profesional yang berdaya saing global, berintegritas, serta mampu berkontribusi tidak hanya pada pembangunan nasional, tetapi juga pada penguatan kapasitas kawasan. 🌏 #IPBUniversity #Reindustrialisasi #ProgramProfesiInsinyur #PPI #PII InsinyurIndonesia InsinyurBerintegritas', 'uploads/beritas/berita_15_pengambilan-sumpah-24-insinyur-ppi-ipb.png', '2026-02-25 02:49:54', 1, '2026-05-22 16:08:25', '2026-05-22 16:08:25');
INSERT INTO beritas (title, category, sub_category, author, excerpt, content, image, published_at, is_active, created_at, updated_at) VALUES ('Persatuan Insinyur Indonesia (PII) Wilayah Jawa Barat menggelar Musyawarah Wilayah (Muswil) ke-3', 'Pelantikan PSPPI', NULL, 'Septya Sekar', 'Persatuan Insinyur Indonesia (PII) Wilayah Jawa Barat menggelar Musyawarah Wilayah (Muswil) ke-3 di Aula Universitas Katolik Parahyangan, Bandung, Senin (16/02/2026). Ir. Hambali, S.T., M.T., M.H., IPM terpilih sebagai Ketua PII Wilayah Jawa Barat periode 2026–2029.', 'Persatuan Insinyur Indonesia (PII) Wilayah Jawa Barat menggelar Musyawarah Wilayah (Muswil) ke-3 di Aula Universitas Katolik Parahyangan, Bandung, Senin (16/02/2026). Ir. Hambali, S.T., M.T., M.H., IPM terpilih sebagai Ketua PII Wilayah Jawa Barat periode 2026–2029. Kepemimpinan baru ini diharapkan mampu memperkuat kolaborasi dengan Pemerintah Provinsi Jawa Barat serta mempererat sinergi 25 Pengurus Cabang PII se-Jawa Barat. Hadir dalam Muswil PII Jabar ini Wakil Ketua Umum PII, Prof. Dr. Ir. Agus Taufik Mulyono, ST., MT., IPU., ASEAN Eng., bersama jajaran Pengurus Pusat PII lainnya. Muswil dihadiri 150 peserta yang terdiri dari unsur Pengurus Pusat PII, Pengurus Wilayah PII, Pengurus Cabang PII se-Jawa Barat, serta undangan dan peninjau. Muswil PII Jawa Barat ini merupakan forum strategis dalam membahas program kerja mendatang, selain memilih Ketua dan Pengurus PII Wilayah Jawa Barat periode 2026–2029. #PII #PIIJabar #MuswilPII #InsinyurIndonesia #KolaborasiUntukNegeri', 'uploads/beritas/berita_16_persatuan-insinyur-indonesia-pii-wilayah.png', '2026-02-20 05:35:36', 1, '2026-05-22 16:08:25', '2026-05-22 16:08:25');
INSERT INTO beritas (title, category, sub_category, author, excerpt, content, image, published_at, is_active, created_at, updated_at) VALUES ('Persatuan Insinyur Indonesia (PII) menjalin kerja sama dengan Universitas Pertamina.', 'MoU', NULL, 'Septya Sekar', 'Ketua Umum Dr.-Ing Ir. Ilham Akbar Habibie, MBA. IPU, ASEAN Eng, dan Rektor Universitas Pertamina Prof.', 'Ketua Umum Dr.-Ing Ir. Ilham Akbar Habibie, MBA. IPU, ASEAN Eng, dan Rektor Universitas Pertamina Prof. Dr. Ir. Wawan Gunawan A. Kadir, MS. IPU. menandatangani Nota Kesepahaman (MoU) di Jakarta, Kamis (12/02/2026). Kerja sama ini sebagai langkah strategis mendukung reindustrialisasi di Indonesia.🤝 Ketua Umum PII, Dr.-Ing Ir. Ilham Akbar Habibie, MBA. IPU, ASEAN Eng, menyampaikan bahwa kerja sama PII dengan universitas di bawah naungan Pertamina ini sebagai kolaborasi mendukung reindustrialisasi di Indonesia melalui pendidikan profesi insinyur, dalam memperkuat peran insinyur di berbagai industri. Direktur Utama PT Pertamina (Persero), Simon Aloysius Mantiri, dalam sambutan menyatakan bahwa masa depan Indonesia tidak hanya ditentukan oleh kekayaan sumber daya alam, tetapi oleh kualitas sumber daya manusianya. Menurutnya Universitas Pertamina memegang peran kunci dalam menjawab tantangan keberlanjutan, karena memiliki kedekatan dengan ekosistem industri dan program magang yang menyiapkan talenta unggul bagi pembangunan. #reindustrialisasi #insinyurindonesia #universitaspertamina #wedjakarta #wed2026', 'uploads/beritas/berita_17_persatuan-insinyur-indonesia-pii-menjali.png', '2026-02-20 05:31:32', 1, '2026-05-22 16:08:25', '2026-05-22 16:08:25');
INSERT INTO beritas (title, category, sub_category, author, excerpt, content, image, published_at, is_active, created_at, updated_at) VALUES ('Ketua Umum PII memimpin Pengambilan Sumpah Profesi Insinyur pada Program Studi Program Profesi Insinyur (PSPPI) di Politeknik Negeri Batam', 'Pelantikan PSPPI', NULL, 'Septya Sekar', 'Ketua Umum Persatuan Insinyur Indonesia (PII) Dr.-Ing. Ir. Ilham Akbar Habibie, MBA., IPU, ASEAN Eng.', 'Ketua Umum Persatuan Insinyur Indonesia (PII) Dr.-Ing. Ir. Ilham Akbar Habibie, MBA., IPU, ASEAN Eng. memimpin Pengambilan Sumpah Profesi Insinyur pada Program Studi Program Profesi Insinyur (PSPPI) di Politeknik Negeri Batam, Kepulauan Riau, Rabu (11/02/2026). Dr.–Ing. Ir. Ilham Akbar Habibie, MBA., IPU, ASEAN Eng. juga menjadi narasumber pada Kuliah Perdana mahasiswa PSPPI Angkatan VII Semester Genap 2025/2026. di Auditorium Lantai 2 Gedung Utama Politeknik Negeri Batam dengan tema “Peran Strategis Insinyur dalam Mitigasi Bencana Akibat Degradasi Hutan di Indonesia.” Momentum ini menjadi penguatan komitmen profesi insinyur dalam menjunjung tinggi integritas, etika, dan tanggung jawab atas lingkungan dan pembangunan berkelanjutan. ✨ Selamat para Insinyur atas Pengambilan Sumpah Profesi Insinyur di PSPPI Politeknik Negeri Batam. Semoga menjadi insinyur yang profesional, berintegritas, dan memberi kontribusi nyata untuk Indonesia. #PersatuanInsinyurIndonesia #PII #PSPPI #SumpahProfesi #InsinyurIndonesia', 'uploads/beritas/berita_18_ketua-umum-pii-memimpin-pengambilan-sump.png', '2026-02-20 05:23:39', 1, '2026-05-22 16:08:25', '2026-05-22 16:08:25');
INSERT INTO beritas (title, category, sub_category, author, excerpt, content, image, published_at, is_active, created_at, updated_at) VALUES ('APLIKASI ASEAN ENGINEER BATCH I/2026 TELAH DIBUKA', 'Sertifikat Internasional', NULL, 'Septya Sekar', '✨ APLIKASI ASEAN ENGINEER BATCH I/2026 TELAH DIBUKA ✨ Persatuan Insinyur Indonesia (PII) membuka Pendaftaran ASEAN Engineer Batch I/2026 dalam rangka Midterm Meeting AFEO. Kesempatan bagi Insinyur Indonesia untuk mendapatkan pengakuan profesional di tingkat ASEAN 🌏⚙️ 🗓 Periode Pendaftaran 23 Januari 2025 – 27 Mei 2026 ⏰ Ditutup Rabu, 27 Mei 2026 pukul 17.00 WIB 📌 Persyaratan: ▪️ Mengisi Form AER Terbaru 2026 ▪️ KTA PII aktif ▪️ SKIP (IPM/IPU) aktif ▪️ Bukti transfer USD 250 📲 Link pendaftaran : ', '✨ APLIKASI ASEAN ENGINEER BATCH I/2026 TELAH DIBUKA ✨ Persatuan Insinyur Indonesia (PII) membuka Pendaftaran ASEAN Engineer Batch I/2026 dalam rangka Midterm Meeting AFEO. Kesempatan bagi Insinyur Indonesia untuk mendapatkan pengakuan profesional di tingkat ASEAN 🌏⚙️ 🗓 Periode Pendaftaran 23 Januari 2025 – 27 Mei 2026 ⏰ Ditutup Rabu, 27 Mei 2026 pukul 17.00 WIB 📌 Persyaratan: ▪️ Mengisi Form AER Terbaru 2026 ▪️ KTA PII aktif ▪️ SKIP (IPM/IPU) aktif ▪️ Bukti transfer USD 250 📲 Link pendaftaran : https://tinyurl.com/PIIAER2026 atau scan QR Code pada poster 📄 Tidak perlu pengiriman hardcopy dokumen. 💳 Pembayaran: Bank Mandiri No. Rekening: 070-00-0994555-6 a.n. Persatuan Insinyur Indonesia ⚠️ Formulir yang dikirim setelah 27 Mei 2026 akan diikutsertakan pada Batch II/2026. 📞 PIC Pendaftaran: PIC : Sdri. Rahma WA : +6282190276169 Email : rahma.lski@pii.or.id / info@pii.or.id #ASEANEngineer #PII #AFEO #InsinyurIndonesia #EngineerASEAN #ProfessionalEngineer', 'uploads/beritas/berita_19_aplikasi-asean-engineer-batch-i2026-tela.jpeg', '2026-02-09 06:38:48', 1, '2026-05-22 16:08:25', '2026-05-22 16:08:25');
INSERT INTO beritas (title, category, sub_category, author, excerpt, content, image, published_at, is_active, created_at, updated_at) VALUES ('PII & Gubernur Pramono Anung Bahas Jakarta Jadi Tuan Rumah WED 2026', 'Audiensi', NULL, 'Septya Sekar', 'Persatuan Insinyur Indonesia (PII) melakukan pertemuan dengan Gubernur DKI Jakarta, Pramono Anung, untuk membahas kesiapan Jakarta sebagai tuan rumah World Engineering Day (WED) 2026 di Kantor Gubernur Jakarta, Kamis (05/02/2026). Pertemuan ini membahas dukungan Pemerintah Provinsi DKI Jakarta terhadap penyelenggaraan WED 2026 sebagai ajang internasional yang menyoroti peran strategis insinyur dalam pembangunan berkelanjutan, inovasi teknologi, dan transformasi perkotaan. PII berharap kolaborasi', 'Persatuan Insinyur Indonesia (PII) melakukan pertemuan dengan Gubernur DKI Jakarta, Pramono Anung, untuk membahas kesiapan Jakarta sebagai tuan rumah World Engineering Day (WED) 2026 di Kantor Gubernur Jakarta, Kamis (05/02/2026). Pertemuan ini membahas dukungan Pemerintah Provinsi DKI Jakarta terhadap penyelenggaraan WED 2026 sebagai ajang internasional yang menyoroti peran strategis insinyur dalam pembangunan berkelanjutan, inovasi teknologi, dan transformasi perkotaan. PII berharap kolaborasi ini dapat memperkuat posisi Jakarta di kancah global sebagai pusat rekayasa, inovasi, dan solusi engineering untuk masa depan. #PII #WorldEngineeringDay2026 #JakartaTuanRumah #WorldEngineeringDay #EngineersForSDGs', 'uploads/beritas/berita_20_pii-gubernur-pramono-anung-bahas-jakarta.jpg', '2026-02-09 03:47:18', 1, '2026-05-22 16:08:25', '2026-05-22 16:08:25');